#include<bits/stdc++.h>
using namespace std;
long long s[100010][210],f[100010];
long long calc(long long x)
{
	long long ans=0;
	while(x)
	{
		ans+=x%10;
		x/=10;
	}
	return ans;
}
int main()
{
	long long t,k;
	scanf("%lld%lld",&t,&k);
	for(long long i=1;i<=200;i++)
	{
		s[i][1]=i;
		s[i][2]=calc(s[i][1]);
		s[i][3]=calc(s[i][2]);
	}
	for(long long i=1;i<=200;i++)
	{
		if(k<=3)
		{
			for(long long j=1;j<=k;j++)
			{
				f[i]+=s[i][j];
			}
		}
		else
		{
			f[i]=s[i][1]+s[i][2]+s[i][3]*(k-2);
		}
	}
	while(t--)
	{
		long long m,ans=0;
		scanf("%lld",&m);
		for(long long i=1;i<=200;i++)
		{
			if(calc(m-f[i])==i)
			{
				ans++;
			}
		}
		printf("%lld\n",ans);
	}
	return 0;
}
